    this.cdr.markForCheck();
  }

  openLogoutConfirm(): void {
    this.showLogoutConfirmModal = true;
    this.cdr.markForCheck();
  }

  cancelLogoutConfirm(): void {
    this.showLogoutConfirmModal = false;
    this.cdr.markForCheck();
  }

  confirmLogout(): void {
    this.showLogoutConfirmModal = false;
    this.auth.logout();
  }

  // ── Tax Summary Section ────────────────────────────────────────────────────

  loadTaxSummary(): void {
    this.taxSummaryLoading = true;
    this.cdr.markForCheck();
    this.apiService.getTaxEvents().subscribe({
      next: (s) => {
        this.taxSummary = s;
        this.taxSummaryLoading = false;
        // Collapse all holdings by default
        this.collapsedHoldings = new Set<number>(
          s.events.map((e: any) => e.holdingId)
        );
        this.cdr.markForCheck();
      },
      error: () => {
        this.taxSummaryLoading = false;
        this.cdr.markForCheck();
      }
    });
  }

  onMarkAllPaid(year?: number): void {
    if (this.sharingCtx.isReadOnly()) return;
    this.taxMarkingAllYear = year ?? 0;
    this.cdr.markForCheck();

    // When a specific year is provided, use the dedicated year-level endpoint
    // so the AnnualTaxSummary status is updated and reflected in the CGT by Year table.
    const call$ = (year != null)
      ? this.apiService.markYearPaid(year) as Observable<unknown>
      : this.apiService.markAllTaxEventsPaid() as Observable<unknown>;

    call$.subscribe({
      next: () => {
        this.taxMarkingAllYear = null;
        this.loadTaxSummary();
      },
      error: () => {
        this.taxMarkingAllYear = null;
        this.cdr.markForCheck();
      }
    });
  }

  recalculateTaxYear(year: number): void {
    if (this.sharingCtx.isReadOnly()) return;
    this.recalculating = true;
    this.taxBannerMessage = null;
    this.cdr.markForCheck();
    this.apiService.recalculateTaxYear(year).subscribe({
      next: (result) => {
        this.recalculating = false;
        if (result.totalTaxDue > 0) {
          this.taxBannerMessage = `Estimated tax due for ${year}: ${this.formatCurrency(result.totalTaxDue)}.`;
        } else {
          this.taxBannerMessage = `No tax due for ${year}.`;
        }
        this.loadTaxSummary();
      },
      error: () => {
        this.recalculating = false;
        this.cdr.markForCheck();
      }
    });
  }

  onMarkSinglePaid(event: TaxEventDto): void {
    if (this.sharingCtx.isReadOnly()) return;
    this.apiService.markTaxEventPaid(event.id).subscribe({
      next: () => this.loadTaxSummary(),
      error: () => {}
    });
  }

  getTaxCurrentYear(): number { return new Date().getFullYear(); }

  getTaxPendingCurrentYear(): number {
    if (!this.taxSummary) return 0;
    const y = this.getTaxCurrentYear();
    // If the CGT year is already marked Paid, nothing is pending
    const cgtYear = this.taxSummary.cgtByYear?.find((r: any) => r.year === y);
    if (cgtYear?.status === 'Paid') return 0;
    // If allowance is configured, use the after-allowance value from allowanceByYear
    if (this.taxSummary.annualTaxFreeAllowance > 0 && this.taxSummary.allowanceByYear) {
      const row = this.taxSummary.allowanceByYear.find((r: any) => r.year === y);
      if (row) return row.taxAfterAllowance;
    }
    // Fall back to raw sum of pending events for the year
    return this.taxSummary.events
      .filter(e => e.status === 'Pending' && new Date(e.eventDate).getFullYear() === y)
      .reduce((s, e) => s + e.taxAmount, 0);
  }

  toggleHoldingCollapsed(holdingId: number): void {
    if (this.collapsedHoldings.has(holdingId)) {
      this.collapsedHoldings.delete(holdingId);
    } else {
      this.collapsedHoldings.add(holdingId);
    }
  }

  isHoldingCollapsed(holdingId: number): boolean {
    return this.collapsedHoldings.has(holdingId);
  }

  getTaxEventsByHolding(): { holdingId: number; ticker: string; etfName: string | null; events: TaxEventDto[] }[] {
    if (!this.taxSummary) return [];
    const map = new Map<number, { holdingId: number; ticker: string; etfName: string | null; events: TaxEventDto[] }>();
    for (const e of this.taxSummary.events) {
      if (!map.has(e.holdingId)) map.set(e.holdingId, { holdingId: e.holdingId, ticker: e.ticker, etfName: e.etfName, events: [] });
      map.get(e.holdingId)!.events.push(e);
    }
    return Array.from(map.values());
  }

  formatTaxEventType(t: string): string {
    return t === 'DeemedDisposal' ? '8-yr Deemed Disposal' : 'Sell';
  }

  getGroupPending(events: TaxEventDto[]): number {
    return events.filter(e => e.status === 'Pending').reduce((s, e) => s + e.taxAmount, 0);
  }


  copyPortfolioTotal(): void {
    if (this.dashboard) {
      this.projectionSettings.startAmount = Math.round(this.dashboard.header.totalHoldingsAmount);
      this.cdr.markForCheck();
    }
  }

  /** Called when the user edits Monthly Buy manually — clears the Target Total field. */
  onMonthlyBuyChange(): void {
    this.targetTotalAmount = null;
    this.cdr.markForCheck();
  }

  /** Called when the user edits Target Total Amount — just clears the derived flag. */
  onTargetTotalChange(): void {
    this.cdr.markForCheck();
  }

  /** Called when the user clicks the "Calculate" button next to Target Total. */
  calculateMonthlyBuyFromTarget(): void {
    if (!this.targetTotalAmount || this.targetTotalAmount <= 0) return;
    const derived = this.deriveMonthlyBuyForTarget(this.targetTotalAmount);
    this.projectionSettings.monthlyBuyAmount = Math.max(0, Math.round(derived));
    this.cdr.markForCheck();
  }

  /**
   * Given a target end portfolio value, reverse-engineers the flat monthly buy amount
   * needed to reach it using the same compound-growth model as the backend.
   *
   * f(M) is linear in M, so:  M = (target - f(0)) / (f(1) - f(0))
   */
  private deriveMonthlyBuyForTarget(target: number): number {
    const s = this.projectionSettings;
    const P = s.startAmount ?? this.dashboard?.header.totalHoldingsAmount ?? 0;
    const R = s.yearlyReturnPercent / 100;
    const I = s.annualBuyIncreasePercent / 100;
    const N = s.projectionYears;

    const today = new Date();
    const currentMonth = today.getMonth() + 1; // 1-based
    // Conservative: assume no buy this month yet
    const monthsRemaining = 13 - currentMonth;
    const partialGrowth = Math.pow(1 + R, monthsRemaining / 12);
    const annualGrowth = 1 + R;

    const endOfYear = (baseM: number): number => {
      let val = (P + monthsRemaining * baseM) * partialGrowth;
      for (let i = 1; i <= N; i++) {
        const increaseFactor = Math.pow(1 + I, i);
        val = (val + 12 * baseM * increaseFactor) * annualGrowth;
      }
      return val;
    };

    const f0 = endOfYear(0);
    const f1 = endOfYear(1);
    const slope = f1 - f0;
    if (slope === 0) return 0;
    return (target - f0) / slope;
  }

}
